={"model":"chat-max","stream":false,"options":{"temperature":0.6,"num_predict":600},"prompt":"You write a personalized cold email to a tech journalist/blogger about AdOff (privacy-first ad blocker Chrome extension, MV3-native, defeats YouTube anti-adblock). This is STEP {{ $json.sequence_step + 1 }} of 4.

Step angles:
1 = intro hook + offer Pro license + 1 specific reason their audience cares (50 words)
2 = useful insight related to their beat, no ask (40 words)
3 = specific story angle pitched (60 words)
4 = break-up email, soft (30 words)

Recipient: {{ $json.name }} ({{ $json.org }})
Their beat: {{ $json.topic_match }}
Language: {{ $json.lang }}

Return JSON ONLY: { "subject": "...", "body": "plain text body, no signature" }
"}

parameters.jsCode:
const orig = $('Pick recipients').itemMatching(0)?.json;
let subject = '', body = '';
try {
  const r = $input.first().json.response || '';
  const parsed = typeof r === 'string' ? JSON.parse(r) : r;
  subject = parsed.subject || '';
  body = parsed.body || '';
} catch(e) {}
body = body + '\n\n---\nThe AdOff team — adoff.app\nUnsubscribe: https://adoff.app/unsub?e=' + encodeURIComponent(orig.email);
return [{ json: { ...orig, subject, body }}];
